import { t as WalletService } from "../../../../chunks/wallet.service.js";
import { fail, redirect } from "@sveltejs/kit";
//#region src/routes/wallet/deposit/+page.server.ts
var load = async ({ locals }) => {
	if (!locals.user) throw redirect(303, "/auth/login");
	return { minDeposit: WalletService.MINIMUM_DEPOSIT };
};
var actions = { default: async ({ request, locals }) => {
	if (!locals.user) throw redirect(303, "/auth/login");
	const formData = await request.formData();
	const amountStr = formData.get("amount");
	const phone = formData.get("phone");
	const amount = parseFloat(amountStr);
	if (isNaN(amount) || amount <= 0) return fail(400, { error: "Please enter a valid deposit amount" });
	if (amount < WalletService.MINIMUM_DEPOSIT) return fail(400, { error: `The minimum deposit amount on our platform is ${WalletService.MINIMUM_DEPOSIT}` });
	if (!phone || !phone.match(/^\+?[1-9]\d{1,14}$/)) return fail(400, { error: "Please enter a valid phone number in international format (+254...)" });
	try {
		const result = await WalletService.initiateMpesaDeposit(locals.user.id, amount, phone);
		if (result.success) return {
			success: true,
			message: result.message
		};
		else return fail(400, { error: result.message });
	} catch (error) {
		return fail(400, { error: error.message || "Payment initiation failed" });
	}
} };
//#endregion
export { actions, load };
